#!/usr/bin/env python3
"""Phase 3 extension: Grade 9, Days 71-80 (fifth Grade 9 batch, continuing
the 10-day pattern past Days 61-70). Topics chosen to avoid any overlap with
the existing Day 1-70 set (see data/grade9.json after the Days 61-70 batch):
paradox and oxymoron, the process essay, semicolons and colons, analogies
and word relationships, nonfiction text structures, clickbait and headline
analysis, the critical review, parallel structure, effective introductions
and conclusions, arithmetic sequences, systems of linear inequalities, the
discriminant, budgeting and net worth, combinations and permutations,
composite 3D solids, rational/irrational/real numbers, absolute value
graphing, vectors, the digestive system, the skeletal and muscular systems,
nanotechnology, thermal energy transfer, the Moon/tides/eclipses, the
nervous system, Punnett squares, ozone depletion, the engineering design
process, and geography extensions (weathering and erosion, site and
situation, central place theory, the Great Lakes, toponymy, housing
affordability, sport mega-events, urban land use models, rural
depopulation).

Subject keys for Grade 9 are "Language", "Math", "Science",
"SocialStudies" (same as earlier batches; SocialStudies content is
geography-focused for Grade 9).

videoUrl is intentionally left unset for every subject -- fetch_video_ids.py
fills these in automatically on its next daily run. No embedded ASCII
double-quote characters are used anywhere in question/summary/option text;
apostrophes and quotation marks use the curly Unicode form (’ “ ”) so they
never collide with the single-quoted Python string literals used here.
"""
import sys
sys.path.insert(0, '/sessions/happy-laughing-ritchie/mnt/gradesbooster')
from gen_curriculum import sub, day, append_to

L9 = 'https://tvolearn.com/pages/grade-9-language'
M9 = 'https://tvolearn.com/pages/grade-9-mathematics'
S9 = 'https://tvolearn.com/pages/grade-9-science-and-technology'
SS9 = 'https://tvolearn.com/pages/grade-9-social-studies'
RL, RM, RS, RSS = (
    'TVO Learn: Grade 9 Language',
    'TVO Learn: Grade 9 Mathematics',
    'TVO Learn: Grade 9 Science & Technology',
    'TVO Learn: Grade 9 Social Studies',
)


def L(t, s, q):
    return sub('Language', t, s, RL, L9, q)


def M(t, s, q):
    return sub('Math', t, s, RM, M9, q)


def Sc(t, s, q):
    return sub('Science', t, s, RS, S9, q)


def SS(t, s, q):
    return sub('SocialStudies', t, s, RSS, SS9, q)


